function autoCat(d) {
  const s = d.toLowerCase();
  if (/debit interest|penal charges|a\/c keeping|nesl|transfer charges|arrear interest|part period inter|chrg\/imps|chrg\/irctc/.test(s)) return "banking";
  if (/insurance/.test(s)) return "insurance";
  if (/withdrawal transfer|loan recovery|o\.s\. deposit|npb repayment/.test(s)) return "loan";
  if (/vision trading|maize|millet|haveri zilla|farmer producer|shri adhishakthi|thammanna|girish s|renukamma|umesha|bhoosiri|krushik|matral|madnoor|subhash|shankarappa|shivappa|kubera|vinay k|mahantesh|gangadhara|rtg\/ashok i|pkgb|roquette/.test(s)) return "raw_materials";
  if (/rootsgoods opc|rootsgoods private limited|rtg\/rootsgo|nft\/rootsgoods/.test(s)) return "intra_company";
  if (/sachin/.test(s)) return "loan";
  if (/zoho|adobe systems|linkedin|openai|chatgpt|claude\.ai|netflix|googleplay|google.*ads|amazon internet|atria convergence|microsb|lepton soft|facebook india/.test(s)) return "it";
  if (/aghub found|aghub/.test(s)) return "outsourcing";
  if (/meghamg|bhoomika h|pradhyumna|nirmala m|santosh b b|k r harish|anand pasch|vishal dev|rajalakshmi|prakash m h|salary dec|qp\/salary/.test(s)) return "salary";
  if (/wipo|ompi|o\.m\.p\.i/.test(s)) return "other";
  if (/nandi service|petrol|petroleum|fuel|service station|mahanth motors/.test(s)) return "other";
  if (/zomato|swiggy|blinkit|restaurant|food/.test(s)) return "other";
  if (/etihad|airbnb|air india|flight/.test(s)) return "other";
  return "";
}
function autoRd(c) { return c==="raw_materials"||c==="it" ? "rd" : c===""?"":"non-rd"; }

function autoCreditCat(d) {
  const s = d.toLowerCase();
  if (/rootsgoods opc|rootsgoods private limited|tfr:.*rootsgoods|rtg.*rootsgoods pvt|nft.*rootsgoods pvt/.test(s)) return "intra_in";
  if (/sbi general insurance/.test(s)) return "refund";
  if (/itdtax refund|fednet refund|visadrefund/.test(s)) return "refund";
  if (/roquette india|hsbcn/.test(s)) return "maize_sales";
  if (/iit ropar/.test(s)) return "govt_project";
  if (/cashfree|yfbk/.test(s)) return "warehouse_sw";
  if (/maize|millet/.test(s)) return "maize_sales";
  if (/sachin/.test(s)) return "other_credit";
  return "other_credit";
}

module.exports = { RAW_DATA, autoCat, autoRd, autoCreditCat };
